export type Item = { kind: "sword" | "amulet" };

export type QuoteStep = { kind: "quote"; items: Item[] };

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
};

export type ScenarioResult = {
  results: unknown[];
};

export function processScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => {
    const item = step.items[0];
    const premium = item.kind === "sword" ? 115 : 71;
    return { kind: "quote", premium };
  });
  return { results };
}
